export class ValidationError extends Error {
  constructor(message: string) {
    super(message);
    this.name = 'ValidationError';
  }
}

export function validateUUID(value: unknown, fieldName: string): string {
  if (typeof value !== 'string') throw new ValidationError(`${fieldName} must be a string`);
  const uuidRegex = /^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i;
  if (!uuidRegex.test(value)) throw new ValidationError(`${fieldName} is not a valid UUID`);
  return value;
}

export function validateString(value: unknown, fieldName: string, opts?: {
  minLength?: number; maxLength?: number; pattern?: RegExp;
}): string {
  if (typeof value !== 'string') throw new ValidationError(`${fieldName} must be a string`);
  const trimmed = value.trim();
  if (opts?.minLength && trimmed.length < opts.minLength) throw new ValidationError(`${fieldName} too short (min ${opts.minLength})`);
  if (opts?.maxLength && trimmed.length > opts.maxLength) throw new ValidationError(`${fieldName} too long (max ${opts.maxLength})`);
  if (opts?.pattern && !opts.pattern.test(trimmed)) throw new ValidationError(`${fieldName} format invalid`);
  return trimmed;
}

export function validateEnum<T extends string>(value: unknown, fieldName: string, allowed: T[]): T {
  if (typeof value !== 'string' || !allowed.includes(value as T)) {
    throw new ValidationError(`${fieldName} must be one of: ${allowed.join(', ')}`);
  }
  return value as T;
}

export function validateNumber(value: unknown, fieldName: string, opts?: {
  min?: number; max?: number; integer?: boolean;
}): number {
  const num = Number(value);
  if (isNaN(num)) throw new ValidationError(`${fieldName} must be a number`);
  if (opts?.integer && !Number.isInteger(num)) throw new ValidationError(`${fieldName} must be an integer`);
  if (opts?.min !== undefined && num < opts.min) throw new ValidationError(`${fieldName} must be >= ${opts.min}`);
  if (opts?.max !== undefined && num > opts.max) throw new ValidationError(`${fieldName} must be <= ${opts.max}`);
  return num;
}

export function validateUrl(value: unknown, fieldName: string, allowedDomains?: string[]): string {
  const str = validateString(value, fieldName, { maxLength: 2048 });
  let url: URL;
  try { url = new URL(str); } catch { throw new ValidationError(`${fieldName} is not a valid URL`); }
  if (url.protocol !== 'https:' && url.protocol !== 'http:') {
    throw new ValidationError(`${fieldName} must use http or https protocol`);
  }
  if (allowedDomains && allowedDomains.length > 0) {
    if (!allowedDomains.some(d => url.hostname === d || url.hostname.endsWith(`.${d}`))) {
      throw new ValidationError(`${fieldName} domain not allowed`);
    }
  }
  return str;
}

export function validateArray<T>(value: unknown, fieldName: string, opts?: {
  minLength?: number; maxLength?: number; itemValidator?: (item: unknown, index: number) => T;
}): T[] {
  if (!Array.isArray(value)) throw new ValidationError(`${fieldName} must be an array`);
  if (opts?.minLength && value.length < opts.minLength) throw new ValidationError(`${fieldName} must have at least ${opts.minLength} items`);
  if (opts?.maxLength && value.length > opts.maxLength) throw new ValidationError(`${fieldName} must have at most ${opts.maxLength} items`);
  if (opts?.itemValidator) return value.map((item, i) => opts.itemValidator!(item, i));
  return value as T[];
}

export function sanitizeHtml(input: string): string {
  return input
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;')
    .replace(/'/g, '&#x27;');
}
