import { supabaseAdmin } from './supabase-admin.ts';

interface RateLimitConfig {
  windowMs: number;
  maxRequests: number;
  keyPrefix: string;
}

interface RateLimitResult {
  allowed: boolean;
  remaining: number;
  resetAt: Date;
}

export async function checkRateLimit(
  key: string,
  config: RateLimitConfig
): Promise<RateLimitResult> {
  const fullKey = `${config.keyPrefix}:${key}`;
  const windowStart = new Date(
    Math.floor(Date.now() / config.windowMs) * config.windowMs
  );
  const resetAt = new Date(windowStart.getTime() + config.windowMs);

  // Upsert the rate limit counter
  const { data, error } = await supabaseAdmin
    .from('rate_limits')
    .upsert(
      { key: fullKey, window_start: windowStart.toISOString(), request_count: 1 },
      { onConflict: 'key,window_start' }
    )
    .select('request_count')
    .single();

  if (error) {
    // If upsert failed, try to increment existing record
    const { data: updated } = await supabaseAdmin
      .rpc('increment_rate_limit', { p_key: fullKey, p_window: windowStart.toISOString() });

    const count = updated ?? 1;
    return {
      allowed: count <= config.maxRequests,
      remaining: Math.max(0, config.maxRequests - count),
      resetAt,
    };
  }

  // If it was an insert (count = 1), we're done
  if (data.request_count === 1) {
    return { allowed: true, remaining: config.maxRequests - 1, resetAt };
  }

  // Otherwise increment
  const { data: incremented } = await supabaseAdmin
    .from('rate_limits')
    .update({ request_count: data.request_count + 1 })
    .eq('key', fullKey)
    .eq('window_start', windowStart.toISOString())
    .select('request_count')
    .single();

  const count = incremented?.request_count ?? data.request_count + 1;
  return {
    allowed: count <= config.maxRequests,
    remaining: Math.max(0, config.maxRequests - count),
    resetAt,
  };
}

// Rate limit configurations for each edge function
export const RATE_LIMITS = {
  customerScan: { windowMs: 60_000, maxRequests: 10, keyPrefix: 'scan' },
  merchantPush: { windowMs: 86_400_000, maxRequests: 5, keyPrefix: 'push' },
  launchCampaign: { windowMs: 3_600_000, maxRequests: 3, keyPrefix: 'launch' },
  checkoutSession: { windowMs: 3_600_000, maxRequests: 5, keyPrefix: 'checkout' },
  audiencePreview: { windowMs: 60_000, maxRequests: 30, keyPrefix: 'preview' },
} as const;
