-- ============================================================
-- AstroLab â€” 009_rate_limiting.sql
-- Rate limiting infrastructure
-- ============================================================

CREATE TABLE IF NOT EXISTS rate_limits (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  key TEXT NOT NULL,
  window_start TIMESTAMPTZ NOT NULL,
  request_count INTEGER DEFAULT 1,
  UNIQUE(key, window_start)
);

CREATE INDEX IF NOT EXISTS idx_rate_limits_key ON rate_limits(key);
CREATE INDEX IF NOT EXISTS idx_rate_limits_window ON rate_limits(window_start);

-- Enable RLS on rate_limits (service_role only)
ALTER TABLE rate_limits ENABLE ROW LEVEL SECURITY;

-- No public policies â€” only service_role can read/write

-- Atomic increment function (avoids race conditions)
CREATE OR REPLACE FUNCTION public.increment_rate_limit(p_key TEXT, p_window TIMESTAMPTZ)
RETURNS INTEGER AS $$
  INSERT INTO rate_limits (key, window_start, request_count)
  VALUES (p_key, p_window, 1)
  ON CONFLICT (key, window_start)
  DO UPDATE SET request_count = rate_limits.request_count + 1
  RETURNING request_count;
$$ LANGUAGE sql VOLATILE SECURITY DEFINER;

-- Cleanup function (call via pg_cron or n8n daily)
CREATE OR REPLACE FUNCTION public.cleanup_rate_limits()
RETURNS void AS $$
  DELETE FROM rate_limits WHERE window_start < now() - INTERVAL '24 hours';
$$ LANGUAGE sql VOLATILE SECURITY DEFINER;
